import{_ as a,c as o,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Licença: Termos BSL Explicados | Plannotator","description":"Aprenda sobre os termos da Business Source License 1.1 (BSL) do Plannotator e as restrições de uso comercial. Entenda os cenários de uso permitidos, planos de mudanças futuras e o cronograma de transição para Apache 2.0 em 2030.","frontmatter":{"title":"Licença: Termos BSL Explicados | Plannotator","sidebarTitle":"Entenda as Regras de Uso Comercial","subtitle":"Licença: Termos BSL Explicados","description":"Aprenda sobre os termos da Business Source License 1.1 (BSL) do Plannotator e as restrições de uso comercial. Entenda os cenários de uso permitidos, planos de mudanças futuras e o cronograma de transição para Apache 2.0 em 2030.","tags":["Licença","BSL-1.1","Uso Comercial"],"prerequisite":[],"order":3},"headers":[],"relativePath":"pt/backnotprop/plannotator/appendix/license/index.md","filePath":"pt/backnotprop/plannotator/appendix/license/index.md"}'),i={name:"pt/backnotprop/plannotator/appendix/license/index.md"};function n(s,e,d,l,c,p){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="explicacao-da-licenca-do-plannotator" tabindex="-1">Explicação da Licença do Plannotator <a class="header-anchor" href="#explicacao-da-licenca-do-plannotator" aria-label="Permalink to &quot;Explicação da Licença do Plannotator&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li>Entender o tipo de licença usada pelo Plannotator e seus termos principais</li><li>Identificar quais cenários de uso são permitidos e quais são restritos</li><li>Conhecer o cronograma de mudanças futuras da licença</li><li>Saber como obter uma licença comercial ou entrar em contato com o licenciante</li></ul><h2 id="o-que-voce-precisa-saber-agora" tabindex="-1">O Que Você Precisa Saber Agora <a class="header-anchor" href="#o-que-voce-precisa-saber-agora" aria-label="Permalink to &quot;O Que Você Precisa Saber Agora&quot;">​</a></h2><p>O Plannotator utiliza a <strong>Business Source License 1.1 (BSL)</strong> como sua licença de código aberto. Esta é uma licença especial projetada para proteger o valor comercial enquanto eventualmente torna o projeto completamente open source.</p><h2 id="termos-principais" tabindex="-1">Termos Principais <a class="header-anchor" href="#termos-principais" aria-label="Permalink to &quot;Termos Principais&quot;">​</a></h2><h3 id="tipo-de-licenca" tabindex="-1">Tipo de Licença <a class="header-anchor" href="#tipo-de-licenca" aria-label="Permalink to &quot;Tipo de Licença&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Conteúdo</th></tr></thead><tbody><tr><td><strong>Nome da Licença</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>Detentor dos Direitos</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>Projeto Licenciado</strong></td><td>plannotator</td></tr><tr><td><strong>Data de Mudança</strong></td><td>2030-01-01</td></tr><tr><td><strong>Licença Após Mudança</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">O que é BSL?</p><p>A Business Source License é uma licença especial desenvolvida pela MariaDB. Ela restringe certos usos comerciais no curto prazo, mas promete converter o software para uma licença totalmente open source (como Apache 2.0) após uma data específica. Este modelo permite que projetos open source obtenham receita sustentável durante a comercialização, garantindo abertura à comunidade no longo prazo.</p></div><h3 id="usos-permitidos" tabindex="-1">Usos Permitidos <a class="header-anchor" href="#usos-permitidos" aria-label="Permalink to &quot;Usos Permitidos&quot;">​</a></h3><p>De acordo com os termos da BSL 1.1, você pode:</p><ul><li><p>✅ <strong>Copiar, modificar e criar trabalhos derivados</strong></p><ul><li>Você pode desenvolver com base no Plannotator</li><li>Pode modificar o código-fonte para atender às suas necessidades</li></ul></li><li><p>✅ <strong>Redistribuir</strong></p><ul><li>Pode distribuir versões originais ou modificadas</li><li>Deve manter os avisos de licença originais</li></ul></li><li><p>✅ <strong>Uso em ambiente não-produtivo</strong></p><ul><li>Desenvolvimento interno, testes e avaliação</li><li>Aprendizado pessoal e pesquisa</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">Uso Amplo para Indivíduos e Empresas</p><p>A definição de &quot;uso em ambiente não-produtivo&quot; da BSL é bastante ampla, incluindo vários cenários para indivíduos e uso interno de empresas. Você e os membros da sua equipe (incluindo contratados independentes) podem usar livremente o Plannotator para desenvolvimento, testes e implantação.</p></div><h3 id="restricoes-de-uso-importante" tabindex="-1">Restrições de Uso (Importante!) <a class="header-anchor" href="#restricoes-de-uso-importante" aria-label="Permalink to &quot;Restrições de Uso (Importante!)&quot;">​</a></h3><p><strong>Restrição Principal</strong>: Não é permitido usar o Plannotator para <strong>Serviços de Planejamento, Contexto ou Aprovação (Planning, Context, or Approval Service)</strong>.</p><h4 id="o-que-e-um-servico-de-planejamento-contexto-ou-aprovacao" tabindex="-1">O que é um &quot;Serviço de Planejamento, Contexto ou Aprovação&quot;? <a class="header-anchor" href="#o-que-e-um-servico-de-planejamento-contexto-ou-aprovacao" aria-label="Permalink to &quot;O que é um &quot;Serviço de Planejamento, Contexto ou Aprovação&quot;?&quot;">​</a></h4><p>Qualquer produto comercial que permita a <strong>terceiros</strong> (exceto funcionários e contratados independentes) acessar as funcionalidades do Plannotator através de operações diretas ou indiretas é considerado um serviço restrito. Isso inclui, mas não se limita a:</p><ul><li><p><strong>Provedores de Serviços em Nuvem</strong></p><ul><li>Plataformas SaaS que oferecem funcionalidades do Plannotator como parte de seus serviços</li><li>Provedores de serviços gerenciados que oferecem Plannotator a clientes ou assinantes</li></ul></li><li><p><strong>Serviços de Infraestrutura</strong></p><ul><li>Provedores de serviços de data center</li><li>Provedores de plataformas de computação em nuvem</li></ul></li><li><p><strong>Terceiros com Serviços Similares</strong></p><ul><li>Incluindo quaisquer serviços fornecidos pelas entidades acima e suas afiliadas</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Aviso de Uso Comercial</p><p>Se você planeja oferecer o Plannotator como parte de um serviço comercial para terceiros, deve obter uma licença comercial antecipadamente. A violação deste termo encerrará automaticamente seus direitos de uso do Plannotator em todas as versões, atuais e futuras.</p></div><h2 id="cronograma-de-mudanca-da-licenca" tabindex="-1">Cronograma de Mudança da Licença <a class="header-anchor" href="#cronograma-de-mudanca-da-licenca" aria-label="Permalink to &quot;Cronograma de Mudança da Licença&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Marco Temporal</th><th>Tipo de Licença</th><th>Descrição</th></tr></thead><tbody><tr><td><strong>Atual - 2030-01-01</strong></td><td>BSL 1.1</td><td>Licença open source com restrições</td></tr><tr><td><strong>A partir de 2030-01-01</strong></td><td>Apache 2.0</td><td>Totalmente open source, sem restrições comerciais</td></tr></tbody></table><h3 id="o-que-acontece-apos-a-mudanca" tabindex="-1">O Que Acontece Após a Mudança? <a class="header-anchor" href="#o-que-acontece-apos-a-mudanca" aria-label="Permalink to &quot;O Que Acontece Após a Mudança?&quot;">​</a></h3><p>A partir de 1º de janeiro de 2030, o Plannotator será automaticamente convertido para a <strong>Apache License 2.0</strong>. Isso significa:</p><ul><li>✅ Todas as restrições comerciais serão removidas</li><li>✅ Pode ser usado livremente para qualquer propósito comercial</li><li>✅ Pode ser integrado a qualquer serviço SaaS</li><li>✅ Conformidade com padrões de licenças open source permissivas</li></ul><h2 id="licenca-comercial" tabindex="-1">Licença Comercial <a class="header-anchor" href="#licenca-comercial" aria-label="Permalink to &quot;Licença Comercial&quot;">​</a></h2><p>Se você precisa usar o Plannotator sem cumprir as restrições da BSL (por exemplo, para serviços de planejamento, contexto ou aprovação), você pode:</p><ol><li><p><strong>Adquirir uma Licença Comercial</strong></p><ul><li>Comprar da backnotprop ou de seus revendedores autorizados</li><li>Obter direitos de uso sem as restrições da BSL</li></ul></li><li><p><strong>Contatar o Licenciante</strong></p><ul><li>Enviar e-mail para: backnotprop</li><li>Descrever seu cenário de uso e necessidades</li></ul></li></ol><h2 id="perguntas-frequentes" tabindex="-1">Perguntas Frequentes <a class="header-anchor" href="#perguntas-frequentes" aria-label="Permalink to &quot;Perguntas Frequentes&quot;">​</a></h2><h3 id="posso-usar-o-plannotator-internamente-na-minha-empresa" tabindex="-1">Posso usar o Plannotator internamente na minha empresa? <a class="header-anchor" href="#posso-usar-o-plannotator-internamente-na-minha-empresa" aria-label="Permalink to &quot;Posso usar o Plannotator internamente na minha empresa?&quot;">​</a></h3><p><strong>Sim.</strong> A BSL permite explicitamente que você e seus funcionários, contratados independentes usem o Plannotator para desenvolvimento interno, testes e implantação. As restrições se aplicam apenas a cenários onde você fornece serviços a <strong>terceiros</strong> (não funcionários e contratados).</p><h3 id="posso-desenvolver-meu-proprio-produto-baseado-no-plannotator" tabindex="-1">Posso desenvolver meu próprio produto baseado no Plannotator? <a class="header-anchor" href="#posso-desenvolver-meu-proprio-produto-baseado-no-plannotator" aria-label="Permalink to &quot;Posso desenvolver meu próprio produto baseado no Plannotator?&quot;">​</a></h3><p><strong>Sim, mas com condições.</strong> Se seu produto é:</p><ul><li>Ferramenta interna: ✅ Permitido</li><li>Projeto pessoal: ✅ Permitido</li><li>Projeto open source: ✅ Permitido (mantendo a licença BSL)</li><li>Produto comercial: ❓ Precisa avaliar se se enquadra como &quot;serviço de planejamento, contexto ou aprovação&quot;</li></ul><h3 id="minha-empresa-e-um-provedor-saas-posso-usar" tabindex="-1">Minha empresa é um provedor SaaS, posso usar? <a class="header-anchor" href="#minha-empresa-e-um-provedor-saas-posso-usar" aria-label="Permalink to &quot;Minha empresa é um provedor SaaS, posso usar?&quot;">​</a></h3><p><strong>Requer licença comercial.</strong> Se seu produto SaaS oferece funcionalidades do Plannotator aos clientes (mesmo como parte de uma funcionalidade maior), isso é considerado um serviço comercial restrito e você deve adquirir uma licença comercial.</p><h3 id="apos-2030-posso-usar-o-plannotator-para-qualquer-finalidade" tabindex="-1">Após 2030, posso usar o Plannotator para qualquer finalidade? <a class="header-anchor" href="#apos-2030-posso-usar-o-plannotator-para-qualquer-finalidade" aria-label="Permalink to &quot;Após 2030, posso usar o Plannotator para qualquer finalidade?&quot;">​</a></h3><p><strong>Sim.</strong> A partir da data de mudança, o Plannotator adotará a licença Apache 2.0, todas as restrições comerciais serão removidas e você poderá usá-lo livremente para qualquer finalidade.</p><h2 id="texto-completo-da-licenca" tabindex="-1">Texto Completo da Licença <a class="header-anchor" href="#texto-completo-da-licenca" aria-label="Permalink to &quot;Texto Completo da Licença&quot;">​</a></h2><p>O texto completo da Business Source License 1.1 pode ser encontrado no arquivo <code>LICENSE</code> no diretório raiz do projeto.</p><h2 id="informacoes-de-contato" tabindex="-1">Informações de Contato <a class="header-anchor" href="#informacoes-de-contato" aria-label="Permalink to &quot;Informações de Contato&quot;">​</a></h2><p>Para licença comercial ou outras questões, entre em contato:</p><ul><li><strong>Licenciante</strong>: backnotprop</li><li><strong>Repositório do Projeto</strong>: <a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="previa-da-proxima-licao" tabindex="-1">Prévia da Próxima Lição <a class="header-anchor" href="#previa-da-proxima-licao" aria-label="Permalink to &quot;Prévia da Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, veremos o <strong><a href="./../../changelog/release-notes/">Registro de Alterações</a></strong>.</p><p>Você verá:</p><ul><li>Histórico de versões do Plannotator</li><li>Novos recursos e melhorias em cada versão</li><li>Correções de bugs importantes</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Declaração da Licença</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>Texto Completo da Licença</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>Informações Principais</strong>:</p><ul><li>Tipo de Licença: Business Source License 1.1 (BSL)</li><li>Detentor dos Direitos: backnotprop (c) 2025</li><li>Data de Mudança: 2030-01-01</li><li>Licença Após Mudança: Apache License, Version 2.0</li><li>Restrição Principal: Não pode ser usado para serviços de planejamento, contexto ou aprovação</li></ul></details>',47)])])}const h=a(i,[["render",n]]);export{m as __pageData,h as default};
